import React from 'react';
import Post from './Post';

function Posts() {
  const posts = [
    { title: 'React Basics', description: 'Learn components and props.' },
    { title: 'State Management', description: 'Understand how state changes the UI.' },
    { title: 'React Router', description: 'Navigate between pages in a React app.' }
  ];

  return (
    <div>
      <h2>Blog Posts</h2>
      {posts.map((post, index) => (
        <Post key={index} title={post.title} description={post.description} />
      ))}
    </div>
  );
}

export default Posts;
